    cp1 = cross_product(p1, p2, p3)
    cp2 = cross_product(p1, p2, p4)
    cp3 = cross_product(p3, p4, p1)
    cp4 = cross_product(p3, p4, p2)

    # General case: segments straddle each other
    if ((cp1 > 0 and cp2 < 0) or (cp1 < 0 and cp2 > 0)) and (
