            "x1": min(zone_xs),
            "x2": max(zone_xs),
            "y1": min(zone_ys),
            "y2": max(zone_ys),
        }

        if (
            abs(zone_bbox["x1"] - edit.x1) < tolerance
            and abs(zone_bbox["x2"] - edit.x2) < tolerance
            and abs(zone_bbox["y1"] - edit.y1) < tolerance
            and abs(zone_bbox["y2"] - edit.y2) < tolerance
        ):
            return VerificationResult(
                verified=True,
                edit_type="NO_GO_ZONE",
                expected=expected,
                actual=zone_bbox,
            )

    return VerificationResult(
        verified=False,
        edit_type="NO_GO_ZONE",
        expected=expected,
        mismatch_reason="No-go zone not found in device map",
    )

def _capture_base_state(self, map_data: MapData) -> None:
    """Capture the base state from map data for rollback and persistence.

    Args:
        map_data: The map data to capture state from.
    """
    # Capture map identifier
    self._map_flag = getattr(map_data, 'map_flag', None)
    self._map_hash = self._calculate_map_hash(map_data)

    # Capture rooms
    if map_data.rooms:
        for room_id, room in map_data.rooms.items():
            if hasattr(room, 'name') and room.name:
                self._original_room_names[room_id] = room.name

    # Capture walls (if exposed by parser)
    walls = getattr(map_data, 'walls', None)
    if walls:
        for wall in walls:
            x1 = getattr(wall, 'x1', getattr(wall, 'x0', None))
            y1 = getattr(wall, 'y1', getattr(wall, 'y0', None))
            x2 = getattr(wall, 'x2', getattr(wall, 'x1', None))
            y2 = getattr(wall, 'y2', getattr(wall, 'y1', None))
            if x1 is not None and y1 is not None and x2 is not None and y2 is not None:
                self._original_walls.append((float(x1), float(y1), float(x2), float(y2)))

    # Capture zones (if exposed by parser)
    no_go_areas = getattr(map_data, 'no_go_areas', getattr(map_data, 'zones', None))
    if no_go_areas:
        for zone in no_go_areas:
            # Note: we simplify to 4-coord bbox for compatibility
            points = getattr(zone, 'points', None)
            if points:
                xs = [float(p.x) for p in points]
                ys = [float(p.y) for p in points]
                self._original_no_go_zones.append((min(xs), min(ys), max(xs), max(ys)))
            else:
                zx1 = getattr(zone, 'x0', getattr(zone, 'x1', None))
                zy1 = getattr(zone, 'y0', getattr(zone, 'y1', None))
                zx2 = getattr(zone, 'x1', getattr(zone, 'x2', None))
                zy2 = getattr(zone, 'y1', getattr(zone, 'y2', None))
                if zx1 is not None and zy1 is not None and zx2 is not None and zy2 is not None:
                    self._original_no_go_zones.append((float(zx1), float(zy1), float(zx2), float(zy2)))

    # Capture mop zones
    no_mop_areas = getattr(map_data, 'no_mop_areas', None)
    if no_mop_areas:
        for mop_zone in no_mop_areas:
            m_points = getattr(mop_zone, 'points', None)
            if m_points:
                m_xs = [float(p.x) for p in m_points]
                m_ys = [float(p.y) for p in m_points]
                self._original_mop_zones.append((min(m_xs), min(m_ys), max(m_xs), max(m_ys)))

