    def cross_product(a: Point, b: Point, c: Point) -> float:
        """Calculate cross product of vectors AB and AC."""
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x)

    def on_segment(a: Point, b: Point, c: Point) -> bool:
